import React, { useMemo } from "react";
import { useUploader } from "../MainUploader";
import { Box, Button, Flex, Image, Text } from "../../../../";
import { Icon } from "../../../../Atoms";
import { useLanguage } from "../../../../../";

const SingleImageUploader = () => {
    const { onPick, files, removeFile, disabled, isClassicUploader } = useUploader();
    const { t } = useLanguage();

    const current = useMemo(() => (files.length ? files[0] : null), [files]);
    const uri =
        current && typeof current.file === "object" && "uri" in current.file
            ? current.file.uri
            : null;

    if (isClassicUploader) {
        return (
            <Flex w={"full"} gap={8} flexDirection={"row"} alignItems={"center"}>
                <Button
                    label={uri ? t("changeImage") : t("chooseImage")}
                    severity={"secondary"}
                    outlined
                    w={'85%'}
                    onClick={onPick as any}
                    disabled={disabled}
                />
                <Button
                    icon="pi pi-times"
                    size={"sm"}
                    severity={"danger"}
                    outlined
                    onClick={removeFile(0)}
                    disabled={!current || disabled}
                />
                {!!current?.name && (
                    <Text as={"span"} fontSize={13} color={"text-secondary"}>
                        {current.name}
                    </Text>
                )}
            </Flex>
        );
    }

    // Non-classic: dashed container with upload icon + phrase, or image preview
    if (uri) {
        return (
            <Box w={"full"}>
                <Flex position={"relative"} w={"full"}>
                    <Image
                        w={"full"}
                        aspectRatio={1.5}
                        objectFit={"contain"}
                        src={uri}
                        alt={"Preview"}
                        borderRadiusLeft={"lg"}
                        borderRadiusRight={"lg"}
                    />
                    <Button
                        icon="pi pi-times"
                        size={"sm"}
                        severity={"danger"}
                        style={{
                            position: "absolute",
                            right: 8,
                            top: 8,
                        }}
                        onClick={removeFile(0)}
                        disabled={disabled}
                    />
                </Flex>
                <Button
                    label={t("changeImage")}
                    severity={"secondary"}
                    outlined
                    w={"full"}
                    mt={8}
                    onClick={onPick as any}
                    disabled={disabled}
                />
            </Box>
        );
    }

    return (
        <Flex
            w={"full"}
            borderWidth={2}
            borderStyle={"dashed"}
            borderColor={"brand.500"}
            borderRadiusLeft={"lg"}
            borderRadiusRight={"lg"}
            alignItems={"center"}
            justifyContent={"center"}
            flexDirection={"column"}
            py={32}
            px={16}
            gap={8}
            onClick={onPick as any}
            opacity={disabled ? 0.5 : 1}
        >
            <Icon name="cloud-upload" size={'lg'} color={"brand.500"} />
            <Text fontSize={14} color={"text-secondary"} textAlign={"center"}>
                {t("tapToUpload")}
            </Text>
        </Flex>
    );
};

export default SingleImageUploader;
